			processOptions();
			if (workingPitch !== undefined) config.pitch = workingPitch;
			if (workingYaw !== undefined) config.yaw = workingYaw;
			if (workingHfov !== undefined) config.hfov = workingHfov;
			fireEvent("scenechange", sceneId);
			load();
